namespace sv_efa91a0dfb1244d0889b805d03dc467e.Client.Auth;

public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_efa91a0dfb1244d0889b805d03dc467e.Client.Auth;

/// <summary>
/// Client-side AuthenticationStateProvider that reads the user info
/// persisted by the server via PersistentComponentState, so auth state
/// survives the transition from server-side prerender to WebAssembly.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authenticationStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState state)
    {
        if (!state.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) || userInfo is null)
        {
            _authenticationStateTask = _unauthenticated;
            return;
        }

        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, userInfo.Email),
            new(ClaimTypes.Email, userInfo.Email),
        };

        foreach (var role in userInfo.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        _authenticationStateTask = Task.FromResult(
            new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(claims, "Persistent"))));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() =>
        _authenticationStateTask;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_efa91a0dfb1244d0889b805d03dc467e.Client.Auth;

namespace sv_efa91a0dfb1244d0889b805d03dc467e.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that returns a hardcoded user
/// and persists the identity via PersistentComponentState so the
/// WebAssembly runtime can restore it after interactive handoff.
/// </summary>
public sealed class PersistingAuthenticationStateProvider
    : AuthenticationStateProvider, IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private static readonly string[] Roles = ["User", "Editor"];
    private const string Email = "bob@example.com";

    private readonly PersistentComponentState _state;
    private readonly PersistingComponentStateSubscription _subscription;

    private Task<AuthenticationState>? _authenticationStateTask;

    public PersistingAuthenticationStateProvider(PersistentComponentState persistentComponentState)
    {
        _state = persistentComponentState;
        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = _state.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);

        // Set the initial hardcoded auth state.
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, Email),
            new(ClaimTypes.Email, Email),
        };

        foreach (var role in Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        var user = new ClaimsPrincipal(new ClaimsIdentity(claims, "Hardcoded"));
        _authenticationStateTask = Task.FromResult(new AuthenticationState(user));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() =>
        _authenticationStateTask ?? throw new InvalidOperationException("Authentication state not initialized.");

    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authenticationStateTask = authenticationStateTask;
        NotifyAuthenticationStateChanged(authenticationStateTask);
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authenticationStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await GetAuthenticationStateAsync();
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var email = principal.FindFirst(ClaimTypes.Email)?.Value ?? principal.Identity.Name!;
            var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

            _state.PersistAsJson(nameof(UserInfo), new UserInfo
            {
                Email = email,
                Roles = roles,
            });
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
    }
}

@page "/profile"
@rendermode InteractiveAuto
@using Microsoft.AspNetCore.Components.Authorization
@inject AuthenticationStateProvider AuthenticationStateProvider

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

@if (_name is not null)
{
    <p><strong>Name:</strong> @_name</p>
    <h4>Roles</h4>
    <ul>
        @foreach (var role in _roles)
        {
            <li>@role</li>
        }
    </ul>
}
else
{
    <p>You are not authenticated.</p>
}

@code {
    private string? _name;
    private string[] _roles = [];

    protected override async Task OnInitializedAsync()
    {
        var state = await AuthenticationStateProvider.GetAuthenticationStateAsync();
        var user = state.User;

        if (user.Identity?.IsAuthenticated == true)
        {
            _name = user.Identity.Name;
            _roles = user.FindAll(System.Security.Claims.ClaimTypes.Role)
                         .Select(c => c.Value)
                         .ToArray();
        }
    }
}

